/**
 * Stats.js - Performance monitoring utility
 * Based on mrdoob/stats.js
 */
(function(global) {
    var PADDING = 8;
    var TEXT_HEIGHT = 12;
    var GRAPH_HEIGHT = 30;

    var mode = 0;
    var modes = [];

    function createStyle() {
        var style = document.createElement('style');
        style.textContent = [
            '.stats {',
            '  position: absolute;',
            '  top: 0;',
            '  left: 0;',
            '  cursor: pointer;',
            '  opacity: 0.9;',
            '  z-index: 10000;',
            '}',
            '.stats-base {',
            '  background: #000;',
            '  padding: ' + PADDING + 'px;',
            '  border-radius: 4px;',
            '  font-family: monospace;',
            '  font-size: 10px;',
            '  line-height: ' + (TEXT_HEIGHT + 1) + 'px;',
            '  color: #fff;',
            '}',
            '.stats-text {',
            '  font-weight: bold;',
            '}',
            '.stats-graph {',
            '  position: relative;',
            '  height: ' + GRAPH_HEIGHT + 'px;',
            '  width: 50px;',
            '  margin-top: 4px;',
            '  background: #333;',
            '  overflow: hidden;',
            '}',
            '.stats-graph canvas {',
            '  position: absolute;',
            '  top: 0;',
            '  left: 0;',
            '}',
            '.stats-label {',
            '  color: #888;',
            '  margin-bottom: 2px;',
            '}'
        ].join('\n');
        var head = document.head || document.getElementsByTagName('head')[0];
        head.appendChild(style);
    }

    function Stats() {
        this.beginTime = performance.now();
        this.prevTime = this.beginTime;
        this.frames = 0;
        this.fps = 0;
        this.fpsMin = Infinity;
        this.fpsMax = -Infinity;
        this.ms = 0;
        this.msMin = Infinity;
        this.msMax = -Infinity;
        this.mem = 0;
        this.memMin = Infinity;
        this.memMax = -Infinity;

        createStyle();

        var container = document.createElement('div');
        container.className = 'stats';
        container.addEventListener('click', function(event) {
            event.preventDefault();
            showPanel(++mode % modes.length);
        }, false);

        // FPS mode
        var fpsDiv = document.createElement('div');
        fpsDiv.className = 'stats-base';
        fpsDiv.style.width = '60px';
        fpsDiv.style.display = 'none';
        fpsDiv.innerHTML = '<div class="stats-label">FPS</div><div class="stats-text" id="stats-fps">0</div><div class="stats-graph"><canvas id="stats-fps-graph" width="50" height="' + GRAPH_HEIGHT + '"></canvas></div>';
        container.appendChild(fpsDiv);
        modes.push({
            name: 'FPS',
            panel: fpsDiv,
            values: [],
            update: function(stats) {
                var fps = stats.fps;
                var fpsGraph = document.getElementById('stats-fps-graph');
                var ctx = fpsGraph.getContext('2d');
                ctx.fillStyle = '#111';
                ctx.fillRect(0, 0, 50, GRAPH_HEIGHT);
                ctx.fillStyle = '#0f0';

                var width = 50;
                var height = GRAPH_HEIGHT;
                var y = height;

                // Draw graph
                var values = this.values;
                var len = Math.min(values.length, width);
                var idx = values.length - len;

                for (var i = 0; i < len; i++) {
                    var v = Math.min(height, Math.max(0, values[idx + i] * height / 100));
                    ctx.fillRect(i, y - v, 1, 2);
                    y -= v;
                }

                document.getElementById('stats-fps').textContent = Math.round(fps);
            }
        });

        // MS mode
        var msDiv = document.createElement('div');
        msDiv.className = 'stats-base';
        msDiv.style.width = '70px';
        msDiv.style.display = 'none';
        msDiv.innerHTML = '<div class="stats-label">MS</div><div class="stats-text" id="stats-ms">0</div><div class="stats-graph"><canvas id="stats-ms-graph" width="50" height="' + GRAPH_HEIGHT + '"></canvas></div>';
        container.appendChild(msDiv);
        modes.push({
            name: 'MS',
            panel: msDiv,
            values: [],
            update: function(stats) {
                var ms = stats.ms;
                var msGraph = document.getElementById('stats-ms-graph');
                var ctx = msGraph.getContext('2d');
                ctx.fillStyle = '#111';
                ctx.fillRect(0, 0, 50, GRAPH_HEIGHT);
                ctx.fillStyle = '#0ff';

                var width = 50;
                var height = GRAPH_HEIGHT;
                var y = height;

                var values = this.values;
                var len = Math.min(values.length, width);
                var idx = values.length - len;

                for (var i = 0; i < len; i++) {
                    var v = Math.min(height, Math.max(0, ms));
                    ctx.fillRect(i, y - v, 1, 2);
                    y -= v;
                }

                document.getElementById('stats-ms').textContent = Math.round(ms);
            }
        });

        // MB mode
        if (performance.memory) {
            var mbDiv = document.createElement('div');
            mbDiv.className = 'stats-base';
            mbDiv.style.width = '80px';
            mbDiv.style.display = 'none';
            mbDiv.innerHTML = '<div class="stats-label">MEM</div><div class="stats-text" id="stats-mem">0</div><div class="stats-graph"><canvas id="stats-mem-graph" width="50" height="' + GRAPH_HEIGHT + '"></canvas></div>';
            container.appendChild(mbDiv);
            modes.push({
                name: 'MEM',
                panel: mbDiv,
                values: [],
                update: function(stats) {
                    var mem = stats.mem;
                    var memGraph = document.getElementById('stats-mem-graph');
                    var ctx = memGraph.getContext('2d');
                    ctx.fillStyle = '#111';
                    ctx.fillRect(0, 0, 50, GRAPH_HEIGHT);
                    ctx.fillStyle = '#f0f';

                    var width = 50;
                    var height = GRAPH_HEIGHT;
                    var y = height;

                    var values = this.values;
                    var len = Math.min(values.length, width);
                    var idx = values.length - len;

                    for (var i = 0; i < len; i++) {
                        var v = Math.min(height, Math.max(0, mem / 1024 / 1024 * height));
                        ctx.fillRect(i, y - v, 1, 2);
                        y -= v;
                    }

                    document.getElementById('stats-mem').textContent = Math.round(stats.mem / 1024 / 1024) + ' MB';
                }
            });
        }

        document.body.appendChild(container);
        this.dom = container;
        this.domElement = container;
        showPanel(0);
    }

    function showPanel(id) {
        mode = id;

        for (var i = 0; i < modes.length; i++) {
            modes[i].panel.style.display = 'none';
        }

        modes[id].panel.style.display = 'block';
        modes[id].values = [];
    }

    Stats.prototype = {
        update: function() {
            var time = performance.now();
            var value = time - this.prevTime;

            this.msMin = Math.min(this.msMin, value);
            this.msMax = Math.max(this.msMax, value);
            this.ms = value;

            modes[1].values.push(value);
            if (modes[1].values.length > 20) modes[1].values.shift();

            this.frames++;

            if (time >= this.prevTime + 1000) {
                this.fps = Math.round((this.frames * 1000) / (time - this.prevTime));
                this.fpsMin = Math.min(this.fpsMin, this.fps);
                this.fpsMax = Math.max(this.fpsMax, this.fps);
                this.frames = 0;
                this.prevTime = time;

                // Memory
                if (performance.memory) {
                    this.mem = performance.memory.usedJSHeapSize;
                    this.memMin = Math.min(this.memMin, this.mem);
                    this.memMax = Math.max(this.memMax, this.mem);
                }

                // Update FPS graph values
                modes[0].values.push(this.fps);
                if (modes[0].values.length > 20) modes[0].values.shift();
            }

            modes[mode].update(this);
        },

        begin: function() {
            this.beginTime = performance.now();
        },

        end: function() {
            this.update();
            return this.beginTime;
        },

        log: function() {
            this.update();
            console.log('FPS: ' + this.fps + ', MS: ' + this.ms);
        }
    };

    global.Stats = Stats;

})(typeof window !== 'undefined' ? window : this);